-- TABLE : DCF_RAWDATA.DATAMART.FACT_DM_MEDICATION_CONSENT
create or replace TABLE FACT_DM_MEDICATION_CONSENT (
	ID NUMBER(10,0) NOT NULL autoincrement start 1 increment 1 order,
	MHP_ID NUMBER(10,0),
	DM_MEDICATION_CONSENT_DETAILS_ID NUMBER(10,0),
	DM_CUS_CUSTODIES_ID NUMBER(10,0),
	DM_CAS_CASES_ID NUMBER(10,0),
	DM_PER_PERSONS_ID NUMBER(10,0),
	MED_MED_ID NUMBER(10,0),
	MHP_REPORT_DATE TIMESTAMP_NTZ(9),
	MEDICATION_START_DATE TIMESTAMP_NTZ(9),
	MEDICATION_END_DATE TIMESTAMP_NTZ(9),
	THRIVE_FAILURE_IND VARCHAR(1),
	PERSON_PRESCRIBER_ID NUMBER(10,0),
	MHB_ADD_USER VARCHAR(20),
	MHB_ADD_TS TIMESTAMP_NTZ(9),
	MHB_ADD_PERSON_ID NUMBER(10,0),
	MHB_ADD_ORGN_ID NUMBER(10,0),
	MHB_MOD_USER VARCHAR(20),
	MHB_MOD_TS TIMESTAMP_NTZ(9),
	MHB_MOD_PERSON_ID NUMBER(10,0),
	MHB_MOD_ORGN_ID NUMBER(10,0),
	DATE_UNKNOWN VARCHAR(1),
	PRESCRIBER_PCS_PCS_ID NUMBER(10,0),
	LAST_REFILL_DATE TIMESTAMP_NTZ(9),
	CONSENT_DATE TIMESTAMP_NTZ(9),
	CONSENT_BY_PERSON_ID NUMBER(10,0),
	MED_ID NUMBER(10,0),
	ROGER_DECISION_DRUG_IND VARCHAR(1),
	MED_ADD_TS TIMESTAMP_NTZ(9),
	MED_ADD_USER VARCHAR(20),
	MED_MOD_TS TIMESTAMP_NTZ(9),
	MED_MOD_USER VARCHAR(20),
	ALLOW_FREQUENCY_NUM NUMBER(38,0),
	UNIT_ORGN_ID NUMBER(10,0),
	AREA_ORGN_ID NUMBER(10,0),
	REGION_ORGN_ID NUMBER(10,0),
	CASE_WORKER_ID NUMBER(10,0),
	CREATED_DATE TIMESTAMP_NTZ(9),
	DELETED_DATE TIMESTAMP_NTZ(9),
	CHECKSUM VARCHAR(99),
	primary key (ID)
);

